    44→function renderMarkdown(text: string): string {
    45→  const lines = text.split("\n");
    46→  const out: string[] = [];
    47→  let inCode = false;
    48→  let inTable = false;
    49→
    50→  for (let i = 0; i < lines.length; i++) {
    51→    const line = lines[i];
    52→
    53→    if (line.startsWith("```")) {
    54→      if (inCode) {
    55→        out.push("</code></pre>");
    56→        inCode = false;
    57→      } else {
    58→        const lang = line.slice(3).trim();
    59→        out.push(`<pre class="bg-navy border border-silver/20 rounded-xl p-4 overflow-x-auto text-xs font-mono text-silver my-3"><code class="language-${lang}">`);
    60→        inCode = true;
    61→      }
    62→      continue;
    63→    }
    64→
    65→    if (inCode) {
    66→      out.push(escapeHtml(line));
    67→      continue;
    68→    }
    69→
    70→    if (line.startsWith("|")) {
    71→      if (!inTable) {
    72→        out.push('<div class="overflow-x-auto my-4"><table class="w-full text-xs border-collapse">');
    73→        inTable = true;
    74→      }
    75→      if (line.replace(/\|/g, "").trim().replace(/-/g, "").trim() === "") {
    76→        continue;
    77→      }
    78→      const cells = line.split("|").filter((_, i, a) => i > 0 && i < a.length - 1);
    79→      const isHeader = i + 1 < lines.length && lines[i + 1]?.includes("---");
    80→      if (isHeader) {
    81→        out.push(`<tr>${cells.map((c) => `<th class="text-left px-3 py-2 text-cool-steel uppercase tracking-wider border-b border-silver/15 font-bold text-[10px]">${inline(c.trim())}</th>`).join("")}</tr>`);
    82→      } else {
    83→        out.push(`<tr class="border-b border-white/3 hover:bg-deep-space/10">${cells.map((c) => `<td class="px-3 py-2 text-silver">${inline(c.trim())}</td>`).join("")}</tr>`);
    84→      }
    85→      continue;
    86→    } else if (inTable) {
    87→      out.push("</table></div>");
    88→      inTable = false;
    89→    }
    90→
    91→    if (line.startsWith("# ")) {
    92→      out.push(`<h1 class="text-2xl font-extrabold text-white mt-6 mb-3">${inline(line.slice(2))}</h1>`);
    93→    } else if (line.startsWith("## ")) {
    94→      out.push(`<h2 class="text-lg font-bold text-white mt-8 mb-3 pb-2 border-b border-silver/15">${inline(line.slice(3))}</h2>`);
    95→    } else if (line.startsWith("### ")) {
    96→      out.push(`<h3 class="text-base font-bold text-silver mt-5 mb-2">${inline(line.slice(4))}</h3>`);
    97→    } else if (line.startsWith("#### ")) {
    98→      out.push(`<h4 class="text-sm font-bold text-silver mt-4 mb-1">${inline(line.slice(5))}</h4>`);
    99→    } else if (line.startsWith("> ")) {
   100→      out.push(`<blockquote class="border-l-2 border-cl-accent/50 pl-4 my-3 text-sm text-cool-steel italic">${inline(line.slice(2))}</blockquote>`);
   101→    } else if (/^- \[[xX]\]/.test(line)) {
   102→      out.push(`<div class="flex items-start gap-2 py-0.5"><span class="w-4 h-4 mt-0.5 flex-shrink-0 rounded bg-cl-accent/20 flex items-center justify-center text-cl-accent text-[10px]">✓</span><span class="text-sm text-cool-steel line-through">${inline(line.replace(/^- \[[xX]\]\s*/, ""))}</span></div>`);
   103→    } else if (/^- \[ \]/.test(line)) {
   104→      out.push(`<div class="flex items-start gap-2 py-0.5"><span class="w-4 h-4 mt-0.5 flex-shrink-0 rounded border border-silver/30"></span><span class="text-sm text-silver">${inline(line.replace(/^- \[ \]\s*/, ""))}</span></div>`);
   105→    } else if (/^[-*] /.test(line)) {
   106→      out.push(`<div class="flex items-start gap-2 py-0.5 pl-1"><span class="w-1.5 h-1.5 mt-2 flex-shrink-0 rounded-full bg-cl-accent/50"></span><span class="text-sm text-silver">${inline(line.replace(/^[-*] /, ""))}</span></div>`);
   107→    } else if (/^\d+\. /.test(line)) {
   108→      const n = line.match(/^(\d+)\./)?.[1];
   109→      out.push(`<div class="flex items-start gap-2 py-0.5 pl-1"><span class="text-xs font-bold text-cl-accent/70 w-5 flex-shrink-0 mt-0.5">${n}.</span><span class="text-sm text-silver">${inline(line.replace(/^\d+\.\s*/, ""))}</span></div>`);
   110→    } else if (line.startsWith("---")) {
   111→      out.push('<hr class="border-silver/15 my-6" />');
   112→    } else if (line.trim() === "") {
   113→      out.push('<div class="h-2"></div>');
   114→    } else {
   115→      out.push(`<p class="text-sm text-silver leading-relaxed my-1">${inline(line)}</p>`);
   116→    }
   117→  }
   118→
   119→  if (inTable) out.push("</table></div>");
   120→  if (inCode) out.push("</code></pre>");
   121→  return out.join("\n");
   122→}
   123→
   124→function escapeHtml(s: string) {
   125→  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
   126→}
   127→
   128→function inline(text: string): string {
   129→  return text
   130→    .replace(/\*\*([^*]+)\*\*/g, "<strong class='text-white font-semibold'>$1</strong>")
   131→    .replace(/\*([^*]+)\*/g, "<em class='text-silver'>$1</em>")
   132→    .replace(/`([^`]+)`/g, "<code class='bg-silver/10 px-1 py-0.5 rounded text-[11px] font-mono text-cl-accent'>$1</code>")
   133→    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, "<a href='$2' target='_blank' rel='noopener' class='text-cl-blue underline'>$1</a>");
   134→}
