    95→/* ─────────────────────────────────────────────────────────────────────────────
    96→   BRAND PALETTE OFICIAL (5 colores)
    97→   #031E43  Prussian Blue  → primary / foreground text
    98→   #3B506D  Dusk Blue      → texto muted / secundario
    99→   #FDFDFB  Off-White      → fondo light / texto claro dark
   100→   #FFFFFF  Pure White     → cards y superficies blancas
   101→   #DDDFE2  Alabaster Grey → bordes, divisores, fondos sutiles
   102→
   103→   HSL conversiones:
   104→   #031E43 → hsl(215 91% 14%)
   105→   #3B506D → hsl(215 30% 33%)
   106→   #FDFDFB → hsl(60 1% 99%)
   107→   #FFFFFF → hsl(0 0% 100%)
   108→   #DDDFE2 → hsl(216 4% 88%)
   109→   ───────────────────────────────────────────────────────────────────────────── */
   110→
   111→/* LIGHT MODE */
   112→:root {
   113→  /* Navy → paleta brand light */
   114→  --theme-white:      #FDFDFB;   /* text-white = Off-White (siempre claro, para texto sobre fondos oscuros) */
   115→  --theme-navy:       #FDFDFB;   /* Off-White */
   116→  --theme-navy-2:     #DDDFE2;   /* Alabaster Grey */
   117→  --theme-navy-3:     #EDEEF0;   /* entre Off-White y Alabaster */
   118→  --theme-navy-card:  #FFFFFF;   /* Cards Pure White sobre fondo Off-White */
   119→  --theme-navy-card2: #FAFAFA;
   120→
   121→  --button-outline: rgba(3,30,67, .12);
   122→  --badge-outline:  rgba(3,30,67, .06);
   123→
   124→  --opaque-button-border-intensity: -8;
   125→
   126→  --elevate-1: rgba(3,30,67, .03);
   127→  --elevate-2: rgba(3,30,67, .07);
   128→
   129→  /* surfaces */
   130→  --background: 60 1% 99%;         /* Off-White #FDFDFB */
   131→  --foreground: 215 91% 14%;       /* Prussian Blue #031E43 */
   132→  --border: 216 4% 88%;            /* Alabaster Grey #DDDFE2 */
   133→  --input: 216 4% 88%;             /* Alabaster Grey */
   134→  --ring: 215 91% 14%;             /* Prussian Blue */
   135→
   136→  /* cards */
   137→  --card: 0 0% 100%;               /* Pure White */
   138→  --card-foreground: 215 91% 14%;
   139→  --card-border: 216 4% 88%;       /* Alabaster Grey */
   140→
   141→  /* popovers */
   142→  --popover: 0 0% 100%;
   143→  --popover-foreground: 215 91% 14%;
   144→  --popover-border: 216 4% 88%;
   145→
   146→  /* primary = Prussian Blue */
   147→  --primary: 215 91% 14%;
   148→  --primary-foreground: 60 1% 99%; /* Off-White */
   149→
   150→  /* secondary = Alabaster Grey */
   151→  --secondary: 216 4% 88%;         /* #DDDFE2 */
   152→  --secondary-foreground: 215 91% 14%;
   153→
   154→  /* muted */
   155→  --muted: 216 4% 88%;             /* Alabaster Grey */
   156→  --muted-foreground: 215 30% 33%; /* Dusk Blue #3B506D */
   157→
   158→  /* accent = Gold (se mantiene) */
   159→  --accent: 215 30% 33%;
   160→  --accent-foreground: 60 1% 99%;
   161→
   162→  --destructive: 0 84% 60%;
   163→  --destructive-foreground: 0 0% 100%;
   164→
   165→  --radius: 0.75rem;
   166→
   167→  /* sidebar */
   168→  --sidebar: 0 0% 100%;
   169→  --sidebar-foreground: 215 91% 14%;
   170→  --sidebar-border: 216 4% 88%;
   171→  --sidebar-primary: 215 91% 14%;
   172→  --sidebar-primary-foreground: 0 0% 100%;
   173→  --sidebar-accent: 216 4% 88%;
   174→  --sidebar-accent-foreground: 215 91% 14%;
   175→  --sidebar-ring: 215 91% 14%;
   176→
   177→  /* charts — derivados del brand */
   178→  --chart-1: 215 30% 33%;           /* Dusk Blue */
   179→  --chart-2: 215 91% 14%;          /* Prussian Blue */
   180→  --chart-3: 215 30% 33%;          /* Dusk Blue */
   181→  --chart-4: 216 4% 88%;           /* Alabaster Grey */
   182→  --chart-5: 215 60% 26%;          /* Prussian Blue intermedio */
   183→}
   184→
   185→/* DARK MODE */
   186→.dark {
   187→  /* Navy → tonos oscuros derivados de Prussian Blue */
   188→  --theme-white:      #FDFDFB;   /* text-white = Off-White en dark */
