   241→  --sidebar: 215 91% 10%;
   242→  --sidebar-foreground: 60 1% 99%;
   243→  --sidebar-border: 216 4% 88%;
   244→  --sidebar-primary: 215 30% 33%;
   245→  --sidebar-primary-foreground: 215 91% 10%;
