] as const;

const builderNav = [
  { to: "/app/builder",     label: "Constructor de Apps",  icon: "ti-wand" },
  { to: "/app/automations", label: "Automatizaciones",     icon: "ti-bolt" },
  { to: "/app/forms",       label: "Formularios",          icon: "ti-forms" },
  { to: "/app/tables",      label: "Tablas",               icon: "ti-table" },
  { to: "/app/pages",       label: "Páginas",              icon: "ti-layout-2" },
] as const;

const configNav = [
  { to: "/app/integrations", label: "Integraciones",         icon: "ti-plug-connected" },
  { to: "/app/services",     label: "Mis Servicios",         icon: "ti-apps" },
  { to: "/app/knowledge",    label: "Base de Conocimiento",  icon: "ti-file-text" },
] as const;

const resourcesNav = [
  { to: "/app/partners",   label: "Partners",   icon: "ti-link" },
  { to: "/app/roi",        label: "ROI",        icon: "ti-trending-up" },
  { to: "/app/studio",     label: "Studio",     icon: "ti-video" },
  { to: "/app/mockups",    label: "Diseños",    icon: "ti-template" },
  { to: "/app/checklist",  label: "Checklist",  icon: "ti-checklist" },
  { to: "/app/research",   label: "Research",   icon: "ti-microscope" },
  { to: "/app/estrategia", label: "Estrategia", icon: "ti-circuit-board" },
  { to: "/app/docs",       label: "Docs",       icon: "ti-book" },
] as const;

const headerNav = [
  { to: "/app/cuenta", label: "Mi Plan", icon: "ti-credit-card" },
] as const;

const titles: Record<string, { title: string; subtitle: string }> = {
  "/app":                      { title: "Panel de Control y Analíticas",        subtitle: "Monitoreo unificado de la suite de automatización Clientum" },
  "/app/connect-whatsapp":     { title: "Conectar WhatsApp",                    subtitle: "Vinculá tu número en 5 minutos — QR, instancia y webhook configurados automáticamente" },
  "/app/agent":                { title: "Configurador de Agente IA",            subtitle: "Definí el perfil, catálogo y FAQs — simulá conversaciones en tiempo real" },
  "/app/analytics":            { title: "Analytics de Leads & Conversaciones",  subtitle: "Desempeño operativo, capturas de leads y métricas por rubro" },
  "/app/chat":                 { title: "Simulador de Chat & Traza RAG",        subtitle: "Probá el bot y observá el razonamiento en tiempo real" },
  "/app/flows":                { title: "Flows de Conversación",                subtitle: "Respuestas automáticas disparadas por palabras clave de tus clientes" },
  "/app/appointments":         { title: "Agenda de Turnos",                     subtitle: "Turnos gestionados por el bot vía WhatsApp" },
  "/app/orders":               { title: "Pedidos por WhatsApp",                 subtitle: "Pedidos creados y gestionados por el bot con actualizaciones automáticas" },
  "/app/broadcast":            { title: "Difusión Masiva",                      subtitle: "Enviá mensajes masivos a tus contactos de WhatsApp" },
  "/app/catalog":              { title: "Catálogo Digital",                     subtitle: "Configurá tu tienda online con productos, marca y contacto" },
  "/app/prospector":           { title: "Prospector de Leads",                  subtitle: "Buscá negocios en Google Maps y agregá prospectos directamente al CRM" },
  "/app/builder":              { title: "Constructor de Apps con IA",           subtitle: "Describí la herramienta que necesitás y la IA la genera automáticamente" },
  "/app/automations":          { title: "Automatizaciones",                     subtitle: "Conectá módulos con triggers y acciones visuales — sin código" },
  "/app/forms":                { title: "Formularios",                          subtitle: "Creá formularios embebibles para tu sitio web y capturá leads" },
  "/app/tables":               { title: "Tablas",                               subtitle: "Bases de datos visuales para gestionar cualquier dato de tu negocio" },
  "/app/pages":                { title: "Páginas",                              subtitle: "Creá y publicá páginas web con el editor de bloques" },
  "/app/crm":                  { title: "CRM & Ventas",                         subtitle: "Pipeline de oportunidades, contactos, empresas y actividades" },
  "/app/projects":             { title: "Gestión de Proyectos",                 subtitle: "Issues, sprints y tablero Kanban al estilo Huly/Linear" },
  "/app/erp":                  { title: "ERP",                                  subtitle: "Cotizaciones, facturas, órdenes de compra e inventario" },
  "/app/team":                 { title: "Equipo & Permisos",                    subtitle: "Miembros, roles, departamentos y registro de actividad" },
  "/app/accounting":           { title: "Contabilidad",                         subtitle: "Libro diario, plan de cuentas, P&L y balance general" },
  "/app/support":              { title: "Soporte al Cliente",                   subtitle: "Tickets, SLA, base de ayuda y métricas de atención" },
  "/app/rrhh":                 { title: "Recursos Humanos",                     subtitle: "Legajos, liquidaciones de sueldos, ausencias y organigrama" },
  "/app/finanzas":             { title: "Finanzas & Tesorería",                 subtitle: "Flujo de caja, cuentas bancarias, transferencias y conciliación" },
  "/app/integrations":         { title: "Integraciones & API Keys",             subtitle: "Configurá las claves de cada servicio que usa Clientum para tu cuenta" },
  "/app/services":             { title: "Mis Servicios",                        subtitle: "Activá y gestioná cada servicio del stack Clientum para tu empresa" },
  "/app/knowledge":            { title: "Base de Conocimiento (RAG)",           subtitle: "Documentos indexados y datos corporativos de prioridad" },
  "/app/cuenta":               { title: "Mi Plan & Facturación",                subtitle: "Administrá tu suscripción, cambiá de plan e historial de pagos" },
  "/app/roi":                  { title: "Mi Ahorro ROI",                        subtitle: "Calculá cuánto te ahorra Clientum cada mes según tu volumen de consultas" },
  "/app/admin":                { title: "Panel de Administración",              subtitle: "Gestión de usuarios, planes y herramientas del sistema — solo admins" },
  "/app/system":               { title: "Monitor del Sistema",                  subtitle: "Estado de servicios, diagnósticos, health checks, logs y alertas — Admin OS" },
  "/app/partners":             { title: "Programa de Partners",                 subtitle: "Referí, revendé o integrá Clientum — generá ingresos recurrentes en pesos" },
  "/app/estrategia":           { title: "Estrategia de Agentes Autónomos",      subtitle: "Ecosistema ERP, arquitectura de integración y hoja de ruta para PyMEs argentinas" },
  "/app/mockups":              { title: "Diseños de Referencia",                subtitle: "Mockups y prototipos del producto — referencia visual de funcionalidades" },
  "/app/docs":                 { title: "Documentación Técnica",                subtitle: "Base de conocimiento, guías de infraestructura y scripts de despliegue" },
  "/app/checklist":            { title: "Checklist de Publicación",             subtitle: "Guías de publicación, Cloudflare Tunnel, comandos de operación y checklist del proyecto" },
  "/app/research":             { title: "Investigación & Repos de Referencia",  subtitle: "Análisis de repos, matrices features/checklist y READMEs de referencia" },
  "/app/studio":               { title: "Studio",                               subtitle: "Creación de contenido multimedia para tu marca" },
};

function isAdmin(email: string | null | undefined) {
  if (!email) return false;
  if (email === "demo@clientum.com.ar") return false;
  return email.endsWith("@clientum.com.ar");
}

const COLLAPSE_KEY = "cl-nav-collapsed";
function loadCollapsed(): Record<string, boolean> {
  try { return JSON.parse(localStorage.getItem(COLLAPSE_KEY) ?? "{}"); }
  catch { return {}; }
}
function saveCollapsed(state: Record<string, boolean>) {
  try { localStorage.setItem(COLLAPSE_KEY, JSON.stringify(state)); } catch { /* noop */ }
}

/* ─────────────── COMPONENTE PRINCIPAL ─────────────── */
export function AppShell({ children }: { children: ReactNode }) {
  const [pathname] = useLocation();
  const meta = titles[pathname] ?? titles["/app"];
  const { user } = useAuth();
  const userIsAdmin = isAdmin(user?.email);
  const { theme, toggleTheme } = useTheme();
  const badges = useSidebarBadges();
  const [sessionExpired, setSessionExpired] = useState(false);

  const [collapsed, setCollapsed] = useState<Record<string, boolean>>(() => {
    const saved = loadCollapsed();
    return { negocio: saved.negocio ?? true, constructor: saved.constructor ?? true, ...saved };
  });

  function toggleCollapse(key: string) {
    setCollapsed(prev => {
      const next = { ...prev, [key]: !prev[key] };
      saveCollapsed(next);
      return next;
    });
  }

  useEffect(() => {
    const handler = () => setSessionExpired(true);
    window.addEventListener("session-expired", handler);
    return () => window.removeEventListener("session-expired", handler);
  }, []);

  function handleSignOut() { window.location.href = "/api/auth/logout"; }

  const displayName = user?.firstName
    ? `${user.firstName}${user.lastName ? " " + user.lastName : ""}`
    : user?.email ?? "Usuario";

  const [notifOpen, setNotifOpen] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) setNotifOpen(false);
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  return (
    <div className="grid grid-cols-[240px_1fr] w-screen h-screen overflow-hidden" style={{ background: "#F1F5F9" }}>

      {/* ═══════════════ SIDEBAR ═══════════════ */}
      <aside
        className="flex flex-col h-full select-none z-10 overflow-y-auto"
        style={{ background: "#FFFFFF", borderRight: "1px solid #E2E8F0" }}
      >
        {/* Logo */}
        <Link
          href="/"
          className="px-4 py-3.5 flex items-center gap-2.5 no-underline flex-shrink-0"
          style={{ borderBottom: "1px solid #E2E8F0" }}
        >
          <div
            className="w-7 h-7 rounded-lg flex items-center justify-center flex-shrink-0"
            style={{ background: "linear-gradient(135deg, #1E40AF, #2563EB)" }}
          >
            <svg viewBox="0 0 48 48" width="16" height="16" fill="none">
              <circle cx="24" cy="8" r="4.5" fill="white" />
              <circle cx="40" cy="24" r="4.5" fill="white" />
              <circle cx="24" cy="40" r="4.5" fill="white" />
              <circle cx="8" cy="24" r="4.5" fill="white" />
              <line x1="24" y1="8" x2="40" y2="24" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <line x1="40" y1="24" x2="24" y2="40" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <line x1="24" y1="40" x2="8" y2="24" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
              <line x1="8" y1="24" x2="24" y2="8" stroke="white" strokeWidth="2.5" strokeLinecap="round" />
            </svg>
          </div>
          <span className="text-sm font-extrabold tracking-tight" style={{ color: "#0F172A" }}>Clientum</span>
        </Link>

        {/* Scroll area */}
        <div className="flex-1 overflow-y-auto py-3">

          {/* Panel General */}
          <div className="px-2 mb-1">
            <Link
              href="/app"
              className={`flex items-center gap-2.5 w-full px-3 py-2 text-[13px] font-semibold rounded-lg transition-all no-underline`}
              style={pathname === "/app" ? {
                background: "#EFF6FF",
                color: "#1D4ED8",
                borderLeft: "2px solid #2563EB",
                paddingLeft: "10px",
              } : {
                color: "#475569",
              }}
              onMouseOver={e => { if (pathname !== "/app") e.currentTarget.style.background = "#F8FAFC"; }}
              onMouseOut={e => { if (pathname !== "/app") e.currentTarget.style.background = "transparent"; }}
            >
              <i className="ti ti-layout-dashboard text-[15px] flex-shrink-0" />
              <span>Panel General</span>
            </Link>
          </div>

          {/* ── WhatsApp & Agente IA ── */}
          <NavGroup
            label="WhatsApp & Agente IA"
            groupKey="agente"
            items={agentNav}
            currentPath={pathname}
            badges={badges}
            collapsed={collapsed["agente"] ?? false}
            onToggle={() => toggleCollapse("agente")}
          />

          {/* ── Operaciones ── */}
          <NavGroup
            label="Operaciones"
            groupKey="operaciones"
            items={operationsNav}
            currentPath={pathname}
            badges={badges}
            collapsed={collapsed["operaciones"] ?? false}
            onToggle={() => toggleCollapse("operaciones")}
          />

          {/* ── Negocio ── */}
          <NavGroup
            label="Negocio"
            groupKey="negocio"
            items={businessNav}
            currentPath={pathname}
            badges={badges}
            collapsed={collapsed["negocio"] ?? true}
            onToggle={() => toggleCollapse("negocio")}
          />

          {/* ── Constructor ── */}
          <NavGroup
            label="Constructor"
            groupKey="constructor"
            items={builderNav}
            currentPath={pathname}
            badges={badges}
            collapsed={collapsed["constructor"] ?? true}
            onToggle={() => toggleCollapse("constructor")}
          />

          {/* ── Configuración ── */}
          <NavGroup
            label="Configuración"
            groupKey="config"
            items={configNav}
            currentPath={pathname}
            badges={badges}
            collapsed={collapsed["config"] ?? false}
            onToggle={() => toggleCollapse("config")}
          />

          {/* Admin */}
          {userIsAdmin && (
            <div className="px-2 mt-1">
              <Link
                href="/app/admin"
                className={`flex items-center gap-2.5 w-full px-3 py-2 text-[13px] font-semibold rounded-lg transition-all no-underline ${
                  pathname.startsWith("/app/admin")
                    ? "bg-violet-50 text-violet-700"
                    : "text-violet-400 hover:text-violet-600 hover:bg-violet-50"
                }`}
              >
                <i className="ti ti-shield-lock text-[15px]" /> Panel Admin
              </Link>
            </div>
          )}
        </div>

        {/* ── Recursos — fondo de sidebar ── */}
        <div
          className="px-2 pt-2 pb-3 flex-shrink-0"
          style={{ borderTop: "1px solid #E2E8F0" }}
        >
          <p className="text-[10px] font-bold uppercase tracking-widest px-3 py-1.5" style={{ color: "#94A3B8" }}>
            Recursos
          </p>
          <nav className="grid grid-cols-4 gap-0.5">
            {resourcesNav.map((it) => {
              const isActive = pathname.startsWith(it.to);
              return (
                <Link
                  key={it.to}
                  href={it.to}
                  title={it.label}
                  className={`flex flex-col items-center gap-1 px-1 py-2 text-[9px] font-semibold rounded-md transition-all no-underline`}
                  style={isActive
                    ? { background: "#EFF6FF", color: "#1D4ED8" }
                    : { color: "#94A3B8" }
                  }
                  onMouseOver={e => { if (!isActive) e.currentTarget.style.background = "#F8FAFC"; e.currentTarget.style.color = "#475569"; }}
                  onMouseOut={e => { if (!isActive) { e.currentTarget.style.background = "transparent"; e.currentTarget.style.color = "#94A3B8"; } }}
                >
                  <i className={`ti ${it.icon} text-sm`} />
                  <span className="truncate w-full text-center leading-tight">{it.label}</span>
                </Link>
              );
            })}
          </nav>
        </div>
      </aside>

      {/* ═══════════════ MAIN ═══════════════ */}
      <main className="flex flex-col h-screen overflow-hidden">

        {/* ── HEADER ── */}
        <header
          className="px-6 flex items-center gap-4 flex-shrink-0"
          style={{
            background: "#FFFFFF",
            borderBottom: "1px solid #E2E8F0",
            minHeight: "52px",
          }}
        >
          {/* Título */}
          <div className="min-w-0 mr-2 flex-1">
            <h1 className="text-[13px] font-bold leading-tight truncate" style={{ color: "#0F172A" }}>
              {meta.title}
            </h1>
            <p className="text-[11px] leading-tight truncate" style={{ color: "#64748B" }}>
              {meta.subtitle}
            </p>
          </div>

          {/* Search */}
          <div className="relative hidden md:block">
            <i className="ti ti-search absolute left-3 top-1/2 -translate-y-1/2 text-sm" style={{ color: "#94A3B8" }} />
            <input
              type="text"
              placeholder="Buscar..."
              className="pl-8 pr-4 py-1.5 rounded-full text-xs border focus:outline-none focus:ring-2 w-44 transition-shadow"
              style={{ borderColor: "#E2E8F0", backgroundColor: "#F8FAFC", color: "#0F172A" }}
              onFocus={e => (e.currentTarget.style.boxShadow = "0 0 0 2px rgba(37,99,235,.2)")}
              onBlur={e => (e.currentTarget.style.boxShadow = "")}
            />
          </div>

          {/* Toggle theme */}
          <button
            onClick={toggleTheme}
            title={theme === "dark" ? "Cambiar a modo claro" : "Cambiar a modo oscuro"}
            className="w-8 h-8 flex items-center justify-center rounded-lg transition-all flex-shrink-0"
            style={{ color: "#64748B" }}
            onMouseOver={e => (e.currentTarget.style.background = "#F1F5F9")}
            onMouseOut={e => (e.currentTarget.style.background = "transparent")}
          >
            {theme === "dark"
              ? <i className="ti ti-sun text-[15px]" />
              : <i className="ti ti-moon text-[15px]" />
            }
          </button>

          {/* Notificaciones */}
          <div className="relative flex-shrink-0" ref={notifRef}>
            <button
              onClick={() => setNotifOpen(v => !v)}
              className="relative w-8 h-8 flex items-center justify-center rounded-lg transition-all"
              style={{ color: "#64748B" }}
              onMouseOver={e => (e.currentTarget.style.background = "#F1F5F9")}
              onMouseOut={e => (e.currentTarget.style.background = "transparent")}
              title="Notificaciones"
            >
              <i className="ti ti-bell text-[15px]" />
              <span className="absolute top-1.5 right-1.5 w-1.5 h-1.5 rounded-full" style={{ backgroundColor: "#2563EB" }} />
            </button>
            {notifOpen && (
              <div className="absolute right-0 top-full mt-2 w-72 rounded-xl shadow-lg border z-50 overflow-hidden"
                style={{ background: "#FFFFFF", borderColor: "#E2E8F0" }}>
                <div className="px-4 py-2.5 border-b" style={{ borderColor: "#E2E8F0" }}>
                  <p className="text-[11px] font-bold" style={{ color: "#0F172A" }}>Notificaciones</p>
                </div>
                {[
                  { icon: "ti-robot",          color: "#2563EB", bg: "#EFF6FF",  msg: "Agente IA respondió 142 mensajes hoy", time: "Hace 5 min" },
                  { icon: "ti-alert-triangle",  color: "#D97706", bg: "#FEF3C7", msg: "TKT-0234 por vencer en 30 min",         time: "Hace 8 min" },
                  { icon: "ti-trending-up",     color: "#059669", bg: "#ECFDF5", msg: "Deal cerrado: Grupo Textil SA — $55K", time: "Hace 22 min" },
                ].map((n, i) => (
                  <div key={i} className="flex items-start gap-3 px-4 py-3 cursor-pointer border-b last:border-0 transition-colors"
                    style={{ borderColor: "#F1F5F9" }}
                    onMouseOver={e => (e.currentTarget.style.background = "#F8FAFC")}
                    onMouseOut={e => (e.currentTarget.style.background = "transparent")}
                  >
                    <div className="w-7 h-7 rounded-lg flex items-center justify-center flex-shrink-0" style={{ backgroundColor: n.bg }}>
                      <i className={`ti ${n.icon} text-sm`} style={{ color: n.color }} />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-[11px] font-medium leading-tight" style={{ color: "#0F172A" }}>{n.msg}</p>
                      <p className="text-[10px] mt-0.5" style={{ color: "#94A3B8" }}>{n.time}</p>
                    </div>
                  </div>
                ))}
                <div className="px-4 py-2.5 text-center">
                  <button className="text-[11px] font-semibold" style={{ color: "#2563EB" }}>Ver todas las notificaciones</button>
                </div>
              </div>
            )}
          </div>

          {/* Nav secundaria + usuario */}
          <div className="flex items-center gap-1 flex-shrink-0">
            {headerNav.map((it) => {
              const isActive = pathname.startsWith(it.to);
              return (
                <Link
                  key={it.to}
                  href={it.to}
                  className={`flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-semibold rounded-lg transition-all no-underline`}
                  style={isActive
                    ? { background: "#EFF6FF", color: "#1D4ED8" }
                    : { color: "#475569" }
                  }
                  onMouseOver={e => { if (!isActive) e.currentTarget.style.background = "#F1F5F9"; }}
                  onMouseOut={e => { if (!isActive) e.currentTarget.style.background = "transparent"; }}
                >
                  <i className={`ti ${it.icon} text-sm`} />
                  {it.label}
                </Link>
              );
            })}

            {userIsAdmin && (
              <Link
                href="/app/admin"
                className={`flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-semibold rounded-lg transition-all no-underline ${
                  pathname.startsWith("/app/admin")
                    ? "bg-violet-50 text-violet-700"
                    : "text-violet-400 hover:text-violet-600 hover:bg-violet-50"
                }`}
              >
                <i className="ti ti-shield-lock text-sm" />
                Admin
              </Link>
            )}

            <div className="w-px h-5 mx-2" style={{ background: "#E2E8F0" }} />

            {user && (
              <div className="flex items-center gap-2">
                {user.profileImageUrl ? (
                  <img src={user.profileImageUrl} alt={displayName} className="w-7 h-7 rounded-full object-cover border border-[#E2E8F0]" />
                ) : (
                  <div className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 text-white"
                    style={{ background: "linear-gradient(135deg, #1E40AF, #2563EB)" }}>
                    {displayName.charAt(0).toUpperCase()}
                  </div>
                )}
                <div className="hidden lg:block min-w-0">
                  <p className="text-[11px] font-semibold truncate max-w-[120px]" style={{ color: "#0F172A" }}>{displayName}</p>
                  {user.email && (
                    <p className="text-[10px] truncate max-w-[120px]" style={{ color: "#64748B" }}>{user.email}</p>
                  )}
                </div>
              </div>
            )}

            <button
              onClick={handleSignOut}
              title="Cerrar sesión"
              className="w-8 h-8 flex items-center justify-center rounded-lg transition-all"
              style={{ color: "#64748B" }}
              onMouseOver={e => (e.currentTarget.style.background = "#F1F5F9")}
              onMouseOut={e => (e.currentTarget.style.background = "transparent")}
            >
              <i className="ti ti-logout text-[15px]" />
            </button>
          </div>
        </header>

        {/* Contenido */}
        <div className="flex-1 overflow-y-auto relative" style={{ background: "#F1F5F9" }}>
          {children}
        </div>

        {/* Sesión expirada */}
        {sessionExpired && (
          <div className="flex-shrink-0 flex items-center gap-4 px-6 py-3 bg-[#1E293B] border-t border-slate-700 animate-in slide-in-from-bottom-2 duration-300">
            <div className="flex items-center gap-3 flex-1 min-w-0">
              <i className="ti ti-lock text-white text-lg flex-shrink-0" />
              <div className="min-w-0">
                <p className="text-sm font-bold text-white leading-tight">Sesión expirada</p>
                <p className="text-xs text-white/70 leading-tight">Tu sesión cerró automáticamente. Iniciá sesión de nuevo para continuar.</p>
              </div>
            </div>
            <div className="flex items-center gap-2 flex-shrink-0">
              <a
                href="/api/login"
                className="inline-flex items-center gap-1.5 px-4 py-1.5 bg-white text-[#0F172A] text-xs font-bold rounded-lg no-underline hover:bg-slate-50 transition-colors"
              >
                <i className="ti ti-login text-sm" />
                Iniciar sesión
              </a>
              <button
                onClick={() => setSessionExpired(false)}
                className="w-7 h-7 flex items-center justify-center text-white/60 hover:text-white hover:bg-white/10 rounded-lg transition-colors"
              >
                <i className="ti ti-x text-sm" />
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

/* ─────────────── badge palette ─────────────── */
const BADGE_COLORS: Record<BadgeVariant, { bg: string; text: string }> = {
  red:    { bg: "#EF4444", text: "#fff" },
  orange: { bg: "#F97316", text: "#fff" },
  yellow: { bg: "#EAB308", text: "#fff" },
  blue:   { bg: "#2563EB", text: "#fff" },
  gold:   { bg: "#D97706", text: "#fff" },
};

/* ─────────────── NavGroup ─────────────── */
type NavItem = { to: string; label: string; icon: string };

function NavGroup({
  label,
  items,
  currentPath,
  badges = {},
  collapsed,
  onToggle,
}: {
  label: string;
  groupKey: string;
  items: readonly NavItem[];
  currentPath: string;
  badges?: BadgeMap;
  collapsed: boolean;
  onToggle: () => void;
}) {
  const hasActive = items.some(it =>
    it.to === "/app" ? currentPath === "/app" : currentPath.startsWith(it.to)
  );

  return (
    <div className="px-2 mb-1">
      <button
        onClick={onToggle}
        className="w-full flex items-center justify-between px-3 py-1.5 rounded-md transition-all"
        style={{ color: hasActive ? "#475569" : "#94A3B8" }}
        onMouseOver={e => (e.currentTarget.style.background = "#F8FAFC")}
        onMouseOut={e => (e.currentTarget.style.background = "transparent")}
        title={collapsed ? `Expandir ${label}` : `Colapsar ${label}`}
      >
        <span className="text-[10px] font-bold uppercase tracking-widest">{label}</span>
        <i className={`ti ti-chevron-right text-[11px] transition-transform duration-200 ${collapsed ? "" : "rotate-90"}`} style={{ color: "#CBD5E1" }} />
      </button>

      {!collapsed && (
        <nav className="space-y-0.5 mt-0.5">
          {items.map((it) => {
            const isActive = it.to === "/app"
              ? currentPath === "/app"
              : currentPath.startsWith(it.to);
            const badge = badges[it.to];
            return (
              <Link
                key={it.to}
                href={it.to}
                className="flex items-center gap-2.5 w-full px-3 py-1.5 text-[13px] font-medium rounded-lg transition-all no-underline"
                style={isActive ? {
                  background: "#EFF6FF",
                  color: "#1D4ED8",
                  borderLeft: "2px solid #2563EB",
                  paddingLeft: "10px",
                  fontWeight: 600,
                } : {
                  color: "#475569",
                }}
                onMouseOver={e => { if (!isActive) { e.currentTarget.style.background = "#F8FAFC"; e.currentTarget.style.color = "#1E293B"; } }}
                onMouseOut={e => { if (!isActive) { e.currentTarget.style.background = "transparent"; e.currentTarget.style.color = "#475569"; } }}
              >
                <i className={`ti ${it.icon} text-[15px] flex-shrink-0`} />
                <span className="flex-1 truncate">{it.label}</span>
                {badge && (
                  <span
                    className="flex-shrink-0 min-w-[18px] h-[18px] px-1 rounded-full text-[10px] font-extrabold flex items-center justify-center leading-none"
                    style={{ backgroundColor: BADGE_COLORS[badge.variant].bg, color: BADGE_COLORS[badge.variant].text }}
                  >
                    {badge.count > 99 ? "99+" : badge.count}
                  </span>
                )}
              </Link>
            );
          })}
        </nav>
      )}

      {collapsed && hasActive && (
        <div className="flex items-center gap-2 px-3 py-1">
          <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ background: "#2563EB" }} />
          <span className="text-[11px] truncate" style={{ color: "#64748B" }}>
            {items.find(it => currentPath.startsWith(it.to))?.label}
          </span>
        </div>
      )}
    </div>
  );
}

